                                                <div className={cn("flex items-center gap-4", isAdmin ? "flex-1" : "w-full mb-auto")}>
                                                    {isSelectionMode && (
                                                        <div
                                                            className={cn(
                                                                "h-6 w-6 rounded-lg flex items-center justify-center transition-all border shrink-0",
                                                                selectedIds.includes(item.id)
                                                                    ? "bg-blue-500 border-blue-500 text-black shadow-lg shadow-blue-500/20"
                                                                    : "bg-white dark:bg-zinc-900 border-zinc-300 dark:border-white/10"
                                                            )}
                                                        >
                                                            {selectedIds.includes(item.id) && <Check className="h-4 w-4" />}
                                                        </div>
                                                    )}
                                                    <button
                                                        onClick={(e) => {
                                                            e.stopPropagation();
                                                            if (isSelectionMode) {
                                                                toggleSelect(item.id);
                                                                return;
                                                            }
                                                            !item.isNotFound && handleToggleTaken(item.id, item.isTaken);
                                                        }}
                                                        disabled={loadingId === item.id}
                                                        className={cn(
                                                            "rounded-xl flex items-center justify-center transition-all shrink-0 shadow-lg group-active:scale-90",
                                                            isAdmin ? "h-10 w-10" : "h-12 w-12",
                                                            item.isNotFound
                                                                ? "bg-red-500 text-white"
                                                                : item.isTaken
                                                                    ? "bg-emerald-500 text-white"
                                                                    : "bg-white/5 text-muted-foreground hover:bg-blue-500 hover:text-white border border-white/5"
                                                        )}
                                                    >
                                                        {loadingId === item.id ? (
                                                            <Clock className={cn(isAdmin ? "w-4 h-4" : "w-6 h-6", "animate-spin")} />
                                                        ) : item.isNotFound ? (
                                                            <X className={isAdmin ? "w-5 h-5" : "w-6 h-6"} />
                                                        ) : item.isTaken ? (
                                                            <CheckCircle2 className={isAdmin ? "w-5 h-5" : "w-6 h-6"} />
                                                        ) : (
                                                            <Circle className={isAdmin ? "w-5 h-5 opacity-20" : "w-6 h-6 opacity-20"} />
                                                        )}
                                                    </button>

                                                    <div className="flex-1 min-w-0">
                                                        <div className={cn("flex items-center gap-3", isAdmin ? "justify-between" : "flex-col items-start")}>
                                                            <div className="min-w-0">
                                                                <h4 className={cn(
                                                                    "font-black text-sm tracking-tight truncate leading-none mb-1 uppercase",
                                                                    item.isTaken ? "text-muted-foreground line-through opacity-40" : "text-zinc-900 dark:text-zinc-100"
                                                                )}>
                                                                    {item.returnTicketId && (
                                                                        <Badge variant="outline" className="bg-indigo-500/10 text-indigo-500 border-indigo-500/20 text-[8px] px-2 py-0.5 font-black flex items-center gap-1 shadow-sm uppercase">
                                                                            <ArrowUpCircle className="w-2 h-2" />
                                                                            İADE GÖREVİ
                                                                        </Badge>
                                                                    )}
                                                                    {getCourierItemDisplayName(item)}
                                                                </h4>
                                                                <div className="flex flex-wrap items-center gap-2">
                                                                    {item.isNotFound && (
                                                                        <Badge variant="outline" className="bg-red-500/10 text-red-500 border-red-500/20 text-[8px] px-2 py-0.5 font-black">
                                                                            BULUNMADI
                                                                        </Badge>
                                                                    )}
                                                                    {!item.isNotFound && getPriorityLabel(item.courierPriorityLabel) !== "NORMAL" && (
                                                                        <Badge variant="outline" className={cn("text-[8px] px-2 py-0.5 font-black border", getPriorityClassName(item.courierPriorityLabel))}>
                                                                            {getPriorityLabel(item.courierPriorityLabel)}
                                                                        </Badge>
                                                                    )}
                                                                    {/* Quantity — big and prominent */}
                                                                    <span className="inline-flex items-center gap-1 bg-blue-500/10 border border-blue-500/20 px-2 py-0.5 rounded-lg">
                                                                        <span className="text-base font-black text-blue-400 leading-none">{getAdjustedQty(item)}</span>
                                                                        <span className="text-[9px] font-black text-blue-400/70 uppercase leading-none">adet</span>
                                                                    </span>
                                                                    <span className="text-[9px] font-black opacity-30 uppercase">
                                                                        {mounted ? new Date(item.createdAt).toLocaleTimeString('tr-TR', { hour: '2-digit', minute: '2-digit' }) : '--:--'}
                                                                    </span>
                                                                    {isAdmin && item.assignedTo && (
                                                                        <Badge className="bg-zinc-500/20 text-zinc-400 border-zinc-500/20 text-[8px] font-black uppercase">
                                                                            {item.assignedTo.name} {item.assignedTo.surname}
                                                                        </Badge>
                                                                    )}
                                                                </div>
                                                            </div>

                                                            {isAdmin && (
                                                                <div className="flex items-center gap-2 shrink-0">
                                                                    {cleanCourierNote(item.notes) && (
                                                                        <div className="max-w-[150px] truncate bg-black/10 px-2 py-1 rounded-lg border border-white/5 text-[9px] text-muted-foreground font-bold italic">
                                                                            {cleanCourierNote(item.notes)}
                                                                        </div>
                                                                    )}
                                                                    <div
                                                                        className="flex items-center bg-zinc-100 dark:bg-white/5 border border-zinc-200 dark:border-white/10 rounded-lg overflow-hidden h-8"
                                                                        onClick={(e) => e.stopPropagation()}
                                                                    >
                                                                        <button
                                                                            onClick={(e) => { e.stopPropagation(); handleUpdateQuantity(item.id, getAdjustedQty(item) - 1); }}
                                                                            disabled={loadingId === item.id}
                                                                            className="h-8 w-7 flex items-center justify-center text-muted-foreground hover:bg-red-500/10 hover:text-red-500 transition-colors font-black text-sm"
                                                                        >−</button>
                                                                        <span className="h-8 min-w-[2rem] px-1 flex items-center justify-center font-black text-sm border-x border-zinc-200 dark:border-white/10">
                                                                            {loadingId === item.id ? <Loader2 className="w-3 h-3 animate-spin" /> : getAdjustedQty(item)}
                                                                        </span>
                                                                        <button
                                                                            onClick={(e) => { e.stopPropagation(); handleUpdateQuantity(item.id, getAdjustedQty(item) + 1); }}
                                                                            disabled={loadingId === item.id}
                                                                            className="h-8 w-7 flex items-center justify-center text-muted-foreground hover:bg-emerald-500/10 hover:text-emerald-500 transition-colors font-black text-sm"
                                                                        >+</button>
                                                                    </div>
                                                                    {item.isTaken && (
                                                                        <Button
                                                                            onClick={(e) => {
                                                                                e.stopPropagation();
                                                                                setApprovingItem({ ...item, quantity: getAdjustedQty(item) });
                                                                                setApproveModalOpen(true);
                                                                            }}
                                                                            disabled={loadingId === item.id}
                                                                            className="bg-emerald-500 hover:bg-emerald-400 text-black font-black text-[9px] tracking-widest rounded-lg h-8 px-4 shadow-lg shadow-emerald-500/20 gap-2 uppercase group"
                                                                        >
                                                                            {loadingId === item.id ? (
                                                                                <Clock className="w-3 h-3 animate-spin" />
                                                                            ) : (
                                                                                <>
                                                                                    <ArrowUpCircle className="w-3 h-3 group-hover:scale-110 transition-transform" />
                                                                                    STOK ONAY
                                                                                </>
                                                                            )}
                                                                        </Button>
                                                                    )}
                                                                    {!item.isTaken && (
                                                                        <Button
                                                                            variant="ghost"
                                                                            size="icon"
                                                                            onClick={(e) => {
                                                                                e.stopPropagation();
                                                                                handleDelete(item.id);
                                                                            }}
                                                                            disabled={loadingId === item.id}
                                                                            className="h-8 w-8 text-rose-500 hover:bg-rose-500 hover:text-white rounded-lg transition-all"
                                                                        >
                                                                            <Trash className="h-4 w-4" />
                                                                        </Button>
                                                                    )}
                                                                </div>
                                                            )}
                                                        </div>
                                                    </div>
                                                </div>

                                                {!isAdmin && (
                                                    <div className="mt-4 flex flex-col gap-2">
                                                        <div onClick={(e) => e.stopPropagation()} className="relative">
                                                            <Select
                                                                value={selectedSuppliers[item.id] || item.supplierId || ""}
                                                                onValueChange={(val) => setSelectedSuppliers(prev => ({ ...prev, [item.id]: val }))}
                                                                disabled={item.isTaken || item.isResolved}
                                                            >
                                                                <SelectTrigger className="h-11 rounded-xl border-zinc-200 dark:border-white/10 bg-zinc-50 dark:bg-white/5 shadow-sm font-black text-[10px] uppercase">
                                                                    <div className="flex items-center gap-2 truncate">
                                                                        <Truck className="w-3.5 h-3.5 text-blue-500 opacity-70" />
                                                                        <SelectValue placeholder="TEDARİKÇİ SEÇ..." />
                                                                    </div>
                                                                </SelectTrigger>
                                                                <SelectContent className="rounded-2xl border-zinc-200 dark:border-white/10 max-h-[250px]">
                                                                    {suppliers.map((s: any) => (
                                                                        <SelectItem key={s.id} value={s.id} className="rounded-xl font-black text-[10px] uppercase cursor-pointer py-3">
                                                                            {s.name}
                                                                        </SelectItem>
                                                                    ))}
                                                                </SelectContent>
                                                            </Select>
                                                        </div>
                                                        <div className="flex gap-2">
                                                            <Button
                                                                variant="outline"
                                                                onClick={(e) => {
                                                                    e.stopPropagation();
                                                                    handleToggleNotFound(item.id, item.isNotFound);
                                                                }}
                                                                disabled={loadingId === item.id || item.isTaken}
                                                                className={cn(
                                                                    "h-11 rounded-xl text-[10px] font-black uppercase tracking-widest flex-1 transition-all",
                                                                    item.isNotFound
                                                                        ? "bg-red-500 text-white border-red-500 shadow-lg shadow-red-500/20"
                                                                        : "border-red-500/20 text-red-500 hover:bg-red-500 hover:text-white"
                                                                )}
                                                            >
                                                                <X className="w-3.5 h-3.5 mr-1.5" />
                                                                {item.isNotFound ? "İşareti Kaldır" : "Bulunamadı"}
                                                            </Button>

